// utils/canvasUtils.ts
export const screenCanvas = (width: number, height: number): any => {
  if (typeof wx !== 'undefined' && wx.createOffscreenCanvas) {
    const canvas = wx.createOffscreenCanvas({ type: '2d', width, height });
    return canvas;
  }
  // Fallback for types (though won't run in pure web without polyfill)
